    //            "a": "0.1",                // volume
    //            "v": "0.1",                // turnover
    //            "ch": "0.21",              // quote change
    //            "i": "0.21" ,              // index price
    //            "m": "0.21",               // mark price
    //            "bp": "0.21",              // bid price
